/// Boltzmann constant [J/K] (exact SI 2019).
pub const K_B: f64 = 1.380649e-23;
/// Standard lab noise temperature [K] (16.85 °C, the "kT" reference).
pub const T_ROOM_K: f64 = 290.0;
/// Default master seed baked in by codegen. `0` → entropy-seeded at Default.
pub const NOISE_MASTER_SEED_DEFAULT: u64 = 0;

pub const NOISE_THERMAL_N: usize = 11;
pub(crate) const NOISE_THERMAL_NODE_I: [usize; NOISE_THERMAL_N] =
    [1, 4, 3, 4, 6, 4, 9, 10, 8, 11, 7];
pub(crate) const NOISE_THERMAL_NODE_J: [usize; NOISE_THERMAL_N] =
    [2, 3, 0, 5, 0, 8, 10, 0, 11, 7, 0];
pub(crate) const NOISE_THERMAL_SQRT_INV_R_DEFAULT: [f64; NOISE_THERMAL_N] = [
    6.74199862463242035e-3,
    7.07106781186547513e-4,
    1.45864991497894570e-3,
    2.58198889747161126e-3,
    5.50481882563180324e-3,
    2.35702260395515839e-2,
    6.08580619450184573e-2,
    3.49215147884789079e-2,
    1.21267812518166488e-2,
    4.22577127364258311e-3,
    3.16227766016837939e-3,
];

#[derive(Clone, Copy, Debug)]
pub struct Xoshiro256pp {
    pub s: [u64; 4],
}

impl Xoshiro256pp {
    #[inline(always)]
    pub fn next_u64(&mut self) -> u64 {
        let result = self.s[0]
            .wrapping_add(self.s[3])
            .rotate_left(23)
            .wrapping_add(self.s[0]);
        let t = self.s[1] << 17;
        self.s[2] ^= self.s[0];
        self.s[3] ^= self.s[1];
        self.s[1] ^= self.s[2];
        self.s[0] ^= self.s[3];
        self.s[2] ^= t;
        self.s[3] = self.s[3].rotate_left(45);
        result
    }
    /// Uniform f64 in [0, 1). Upper 53 bits of the u64.
    #[inline(always)]
    pub fn next_f64(&mut self) -> f64 {
        (self.next_u64() >> 11) as f64 * (1.0 / (1u64 << 53) as f64)
    }
}

#[inline(always)]
fn splitmix64(state: &mut u64) -> u64 {
    *state = state.wrapping_add(0x9E3779B97F4A7C15);
    let mut z = *state;
    z = (z ^ (z >> 30)).wrapping_mul(0xBF58476D1CE4E5B9);
    z = (z ^ (z >> 27)).wrapping_mul(0x94D049BB133111EB);
    z ^ (z >> 31)
}

/// Seed an array of Xoshiro256pp streams from one master seed via SplitMix64.
/// Every stream gets statistically independent state — no cross-source correlation.
fn seed_noise_rngs<const N: usize>(master: u64) -> [Xoshiro256pp; N] {
    seed_noise_rngs_salted::<N>(master, 0)
}

/// Seed an array of Xoshiro256pp streams with an additional 64-bit salt.
/// Used to derive per-phase streams (thermal vs shot) from one master
/// seed without any cross-phase prefix overlap. Salt is XORed into the
/// SplitMix64 state after the standard entropy resolution.
fn seed_noise_rngs_salted<const N: usize>(master: u64, salt: u64) -> [Xoshiro256pp; N] {
    let mut sm = if master == 0 {
        // master=0 → entropy from system clock. Plugin hosts wanting
        // determinism should call set_seed(nonzero) before processing.
        std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_nanos() as u64)
            .unwrap_or(0x0123456789ABCDEF)
    } else {
        master
    };
    sm ^= salt;
    // First mix to avoid weak seeds
    let _ = splitmix64(&mut sm);
    let mut out = [Xoshiro256pp { s: [0; 4] }; N];
    for k in 0..N {
        out[k].s[0] = splitmix64(&mut sm);
        out[k].s[1] = splitmix64(&mut sm);
        out[k].s[2] = splitmix64(&mut sm);
        out[k].s[3] = splitmix64(&mut sm);
        // xoshiro requires at least one nonzero state word.
        if out[k].s == [0; 4] {
            out[k].s[0] = 1;
        }
    }
    out
}

/// Shot-noise salt. Distinct 64-bit constant applied to the master
/// seed so shot streams do not share any prefix with thermal streams
/// under a deterministic seed. Chosen to be a high-entropy value.
pub const NOISE_SHOT_SALT: u64 = 0xA5A5_DEAD_BEEF_CAFE;

/// Standard-normal (µ=0, σ=1) sample via Marsaglia polar method.
/// One RNG pair yields two Gaussians; the second is cached for the next call.
#[inline(always)]
fn gaussian(rng: &mut Xoshiro256pp, cache: &mut Option<f64>) -> f64 {
    if let Some(z) = cache.take() {
        return z;
    }
    loop {
        let u = 2.0 * rng.next_f64() - 1.0;
        let v = 2.0 * rng.next_f64() - 1.0;
        let s = u * u + v * v;
        if s > 0.0 && s < 1.0 {
            let factor = (-2.0 * s.ln() / s).sqrt();
            *cache = Some(v * factor);
            return u * factor;
        }
    }
}

