/// DC operating point: steady-state node voltages
pub const DC_OP: [f64; N] = [
    0.00000000000000000e0,
    0.00000000000000000e0,
    2.83500489713848136e0,
    1.50000000000000000e1,
    4.31476019254251497e0,
    2.27524516962194134e0,
    5.44953372931392543e0,
    8.87184131136244147e0,
    3.65408699255688107e0,
    2.74894617732846358e0,
    8.50127292290361147e0,
    -3.48185004939979186e-3,
];

/// DC operating point: nonlinear device currents at bias point
pub const DC_NL_I: [f64; M] = [
    -2.52283500489713877e-9,
    6.88987790287620754e-5,
    3.35003724468283881e-3,
];

/// Circuit state for one processing channel.
///
/// Contains both per-sample state (v_prev, i_nl_prev) and sample-rate-dependent
/// matrices (s, a_neg, k, s_ni). Call [`set_sample_rate`](CircuitState::set_sample_rate)
/// before processing if the host sample rate differs from [`SAMPLE_RATE`].
#[derive(Clone, Debug)]
pub struct CircuitState {
    /// Previous node voltages v[n-1]
    pub v_prev: [f64; N],

    /// Previous nonlinear currents i_nl[n-1]
    pub i_nl_prev: [f64; M],

    /// Nonlinear currents from two samples ago i_nl[n-2] (for NR predictor)
    pub i_nl_prev_prev: [f64; M],

    /// DC operating point (for reset/sleep/wake)
    pub dc_operating_point: [f64; N],

    /// Previous input sample for trapezoidal integration
    pub input_prev: f64,

    /// Iteration count from last solve (for diagnostics)
    pub last_nr_iterations: u32,

    /// Diagnostic: peak absolute output (pre-clamp)
    pub diag_peak_output: f64,
    /// Diagnostic: number of times output exceeded ±10V
    pub diag_clamp_count: u64,
    /// Diagnostic: number of times NR hit max iterations
    pub diag_nr_max_iter_count: u64,
    /// Diagnostic: number of times NaN triggered state reset
    pub diag_nan_reset_count: u64,
    /// Diagnostic: number of times matrix inversion detected a singular matrix
    pub diag_singular_matrix_count: u64,
    /// Diagnostic: number of samples hit by the global voltage-damping safety
    /// net. Per CLAUDE.md ("never use output attenuation to mask simulation
    /// errors"), any nonzero value here is a symptom to investigate, not an
    /// acceptable steady-state.
    pub diag_voltage_damp_count: u64,
    /// Diagnostic: number of times sub-step NR was used (nodal full-LU only;
    /// always 0 on the DK path)
    pub diag_substep_count: u64,

    /// S = A^{-1} matrix, recomputed by set_sample_rate
    pub s: [[f64; N]; N],

    /// A_neg = alpha*C - G matrix, recomputed by set_sample_rate
    pub a_neg: [[f64; N]; N],

    /// K = N_v * S * N_i kernel matrix, recomputed by set_sample_rate
    pub k: [[f64; M]; M],

    /// S * N_i product, recomputed by set_sample_rate
    pub s_ni: [[f64; M]; N],

    /// S_be = A_be^{-1} (backward Euler), recomputed by set_sample_rate
    pub s_be: [[f64; N]; N],

    /// K_be = N_v * S_be * N_i (backward Euler kernel), recomputed by set_sample_rate
    pub k_be: [[f64; M]; M],

    /// S_be * N_i product (backward Euler), recomputed by set_sample_rate
    pub s_ni_be: [[f64; M]; N],

    /// A_neg_be = (1/T)*C (backward Euler history), recomputed by set_sample_rate
    pub a_neg_be: [[f64; N]; N],

    /// BE cooldown: remaining samples to force backward Euler after ringing detected.
    /// Decays to 0, then trapezoidal resumes. Prevents trap→BE→trap oscillation.
    pub be_cooldown: u32,

    /// Diagnostic: number of backward Euler fallback activations
    pub diag_be_fallback_count: u64,

    /// Potentiometer 0 current resistance (ohms)
    pub pot_0_resistance: f64,
    /// Potentiometer 0 previous timestep resistance (for trapezoidal A_neg correction)
    pub pot_0_resistance_prev: f64,

    /// Current sample rate (needed for rebuild_matrices)
    pub current_sample_rate: f64,
    /// Lazy rebuild flag: set by set_pot/set_switch, cleared by process_sample
    pub matrices_dirty: bool,

    // --- Runtime-adjustable device parameters ---
    // These fields are initialized from the corresponding DEVICE_N_* constants.
    // Modify them at runtime to change device behavior (e.g. tube aging, transistor matching).
    /// Device 0 IS (Diode) — runtime adjustable
    pub device_0_is: f64,

    /// Device 0 N_VT (Diode) — runtime adjustable
    pub device_0_n_vt: f64,

    /// Device 1 IS (Bjt) — runtime adjustable
    pub device_1_is: f64,

    /// Device 1 VT (Bjt) — runtime adjustable
    pub device_1_vt: f64,

    /// Device 1 BETA_F (Bjt) — runtime adjustable
    pub device_1_bf: f64,

    /// Device 1 BETA_R (Bjt) — runtime adjustable
    pub device_1_br: f64,

    /// Device 2 IS (Bjt) — runtime adjustable
    pub device_2_is: f64,

    /// Device 2 VT (Bjt) — runtime adjustable
    pub device_2_vt: f64,

    /// Device 2 BETA_F (Bjt) — runtime adjustable
    pub device_2_bf: f64,

    /// Device 2 BETA_R (Bjt) — runtime adjustable
    pub device_2_br: f64,

    // --- Authentic circuit noise (Phase 1: thermal) ---
    /// Per-source xoshiro256++ state — independent streams, no cross-correlation.
    pub noise_rng: [Xoshiro256pp; NOISE_THERMAL_N],
    /// Cached second Gaussian from Marsaglia polar pair.
    pub noise_gaussian_cache: [Option<f64>; NOISE_THERMAL_N],
    /// Master noise switch — runtime. Default false (opt-in).
    pub noise_enabled: bool,
    /// Master scalar applied to every noise source.
    pub noise_gain: f64,
    /// Scalar applied only to Johnson-Nyquist thermal sources.
    pub thermal_gain: f64,
    /// Circuit temperature [K]. Runtime-settable.
    pub temperature_k: f64,
    /// Master seed recorded for reset() re-derivation.
    pub noise_master_seed: u64,
    /// Precomputed sqrt(8·K_B·T·fs_internal). Halved in the two-draw stamp
    /// (each draw uses scale/2 so consecutive-draw sum preserves kTC; see
    /// NOISE.md 'Constant derivation' and 'Nyquist anti-aliasing' sections).
    pub noise_thermal_scale: f64,
    /// Effective internal sample rate (host_rate × OVERSAMPLING_FACTOR).
    /// Tracked so `set_temperature_k` can recompute `noise_thermal_scale`.
    pub noise_fs: f64,
    /// Per-source `sqrt(1/R)` — live mirror of `NOISE_THERMAL_SQRT_INV_R_DEFAULT`.
    /// Static entries stay at their baked value. Dynamic entries (`.pot` /
    /// `.wiper` / `.runtime R` members) are refreshed inside the matching
    /// `set_pot_N` / `set_runtime_R_<field>` setter.
    pub noise_thermal_sqrt_inv_r: [f64; NOISE_THERMAL_N],
    /// Per-source previous-draw buffer for the two-draw Nyquist-anti-alias
    /// scheme. Each thermal stamp uses `w_new + w_prev` where w_new is the
    /// current draw (amplitude scale/2) and w_prev is the previous draw.
    /// Zeroed at default() and reset(). See NOISE.md 'Nyquist anti-aliasing'.
    pub noise_thermal_w_prev: [f64; NOISE_THERMAL_N],
}

impl Default for CircuitState {
    fn default() -> Self {
        // Noise state (thermal only in Phase 1)
        let fs_internal = SAMPLE_RATE * OVERSAMPLING_FACTOR as f64;
        let noise_thermal_scale = (8.0 * K_B * T_ROOM_K * fs_internal).sqrt();
        let noise_rng = seed_noise_rngs::<NOISE_THERMAL_N>(NOISE_MASTER_SEED_DEFAULT);
        Self {
            v_prev: DC_OP,
            i_nl_prev: DC_NL_I,
            i_nl_prev_prev: DC_NL_I,
            dc_operating_point: DC_OP,
            input_prev: 0.0,
            last_nr_iterations: 0,
            diag_peak_output: 0.0,
            diag_clamp_count: 0,
            diag_nr_max_iter_count: 0,
            diag_nan_reset_count: 0,
            diag_singular_matrix_count: 0,
            diag_voltage_damp_count: 0,
            diag_substep_count: 0,
            s: S_DEFAULT,
            a_neg: A_NEG_DEFAULT,
            k: K_DEFAULT,
            s_ni: S_NI_DEFAULT,

            s_be: S_BE_DEFAULT,
            k_be: K_BE_DEFAULT,
            s_ni_be: S_NI_BE_DEFAULT,
            a_neg_be: A_NEG_BE_DEFAULT,
            be_cooldown: 0,

            diag_be_fallback_count: 0,

            pot_0_resistance: 9.99999999999999854e4,
            pot_0_resistance_prev: 9.99999999999999854e4,

            current_sample_rate: SAMPLE_RATE,
            matrices_dirty: false,

            device_0_is: DEVICE_0_IS,

            device_0_n_vt: DEVICE_0_N_VT,

            device_1_is: DEVICE_1_IS,

            device_1_vt: DEVICE_1_VT,

            device_1_bf: DEVICE_1_BETA_F,

            device_1_br: DEVICE_1_BETA_R,

            device_2_is: DEVICE_2_IS,

            device_2_vt: DEVICE_2_VT,

            device_2_bf: DEVICE_2_BETA_F,

            device_2_br: DEVICE_2_BETA_R,

            noise_rng,
            noise_gaussian_cache: [None; NOISE_THERMAL_N],
            noise_enabled: false,
            noise_gain: 1.0,
            thermal_gain: 1.0,
            temperature_k: T_ROOM_K,
            noise_master_seed: NOISE_MASTER_SEED_DEFAULT,
            noise_thermal_scale,
            noise_fs: fs_internal,
            noise_thermal_sqrt_inv_r: NOISE_THERMAL_SQRT_INV_R_DEFAULT,
            noise_thermal_w_prev: [0.0; NOISE_THERMAL_N],
        }
    }
}

impl CircuitState {
    /// Reset to DC operating point
    pub fn reset(&mut self) {
        self.v_prev = self.dc_operating_point;
        self.i_nl_prev = DC_NL_I;
        self.i_nl_prev_prev = DC_NL_I;
        self.input_prev = 0.0;
        self.last_nr_iterations = 0;
        self.diag_peak_output = 0.0;
        self.diag_clamp_count = 0;
        self.diag_nr_max_iter_count = 0;
        self.diag_nan_reset_count = 0;
        self.diag_singular_matrix_count = 0;
        self.diag_voltage_damp_count = 0;
        self.diag_substep_count = 0;
        self.diag_be_fallback_count = 0;

        self.be_cooldown = 0;

        self.pot_0_resistance = 9.99999999999999854e4;
        self.pot_0_resistance_prev = 9.99999999999999854e4;

        self.device_0_is = DEVICE_0_IS;

        self.device_0_n_vt = DEVICE_0_N_VT;

        self.device_1_is = DEVICE_1_IS;

        self.device_1_vt = DEVICE_1_VT;

        self.device_1_bf = DEVICE_1_BETA_F;

        self.device_1_br = DEVICE_1_BETA_R;

        self.device_2_is = DEVICE_2_IS;

        self.device_2_vt = DEVICE_2_VT;

        self.device_2_bf = DEVICE_2_BETA_F;

        self.device_2_br = DEVICE_2_BETA_R;

        // Re-seed noise RNGs (keeps noise_enabled, gains, temperature untouched).
        self.noise_rng = seed_noise_rngs::<NOISE_THERMAL_N>(self.noise_master_seed);
        self.noise_gaussian_cache = [None; NOISE_THERMAL_N];
        // Restore per-source sqrt(1/R) to defaults. Dynamic sources will
        // be re-updated by any subsequent set_pot_N / set_runtime_R call;
        // this mirrors how reset() restores pot_<i>_resistance to nominal.
        self.noise_thermal_sqrt_inv_r = NOISE_THERMAL_SQRT_INV_R_DEFAULT;
        // Clear two-draw buffer so silence after reset produces true zero output.
        self.noise_thermal_w_prev = [0.0; NOISE_THERMAL_N];
    }

    /// Set DC operating point (call after DC analysis)
    pub fn set_dc_operating_point(&mut self, v_dc: [f64; N]) {
        self.dc_operating_point = v_dc;
        self.v_prev = v_dc;
    }

    /// Read the baked DC operating point for this circuit.
    ///
    /// This is the solution to the nonlinear DC system computed at codegen
    /// time (at nominal pot/switch values) and frozen into the `DC_OP`
    /// constant. Prefer this over `v_prev` when you want the *designed*
    /// bias point — `v_prev` carries per-sample dynamics plus any updates
    /// from `set_dc_operating_point` / `recompute_dc_op`.
    ///
    /// For per-node access with readable names, see [`dc_op_dump`].
    #[inline]
    pub fn dc_op(&self) -> &[f64; N] {
        &self.dc_operating_point
    }

    /// Pretty-print the DC operating point with user-assigned node names.
    ///
    /// Writes one line per named node to `stderr` in the form
    /// `  V(node_name) = +X.XXX V`. Useful for sanity-checking circuit
    /// bias during plugin bring-up. Internal / augmented nodes (VS/VCVS
    /// branch currents, transformer windings) are not emitted — they have
    /// no stable user-facing name.
    ///
    /// Call order-of-magnitude-free: formatting allocates. Not meant for
    /// the audio thread.
    pub fn dc_op_dump(&self) {
        let dc = &self.dc_operating_point;
        eprintln!("  V(IN) = {:+.4} V", dc[0]);
        eprintln!("  V(MID_IN) = {:+.4} V", dc[1]);
        eprintln!("  V(BASE1) = {:+.4} V", dc[2]);
        eprintln!("  V(VCC) = {:+.4} V", dc[3]);
        eprintln!("  V(COLL1) = {:+.4} V", dc[4]);
        eprintln!("  V(EMIT1) = {:+.4} V", dc[5]);
        eprintln!("  V(FB) = {:+.4} V", dc[6]);
        eprintln!("  V(COLL2) = {:+.4} V", dc[7]);
        eprintln!("  V(EMIT2A) = {:+.4} V", dc[8]);
        eprintln!("  V(EMIT2B) = {:+.4} V", dc[9]);
        eprintln!("  V(OUT) = {:+.4} V", dc[10]);
    }

    /// Recompute all sample-rate-dependent matrices for a new sample rate.
    ///
    /// Call this once during plugin initialization (NOT on the audio thread).
    /// This recomputes S, A_neg, K, S*N_i, inductor g_eq, and pot SM vectors
    /// from the stored G and C matrices.
    ///
    /// If `sample_rate` matches [`SAMPLE_RATE`], this is a no-op (the defaults
    /// are already correct).
    pub fn set_sample_rate(&mut self, sample_rate: f64) {
        if !(sample_rate > 0.0 && sample_rate.is_finite()) {
            return; // Invalid sample rate, keep defaults
        }
        // Noise: recompute sqrt(4·K_B·T·fs_internal) for the new rate.
        self.noise_fs = sample_rate * OVERSAMPLING_FACTOR as f64;
        self.noise_thermal_scale = (8.0 * K_B * self.temperature_k * self.noise_fs).sqrt();

        self.current_sample_rate = sample_rate;

        // If same as codegen sample rate AND all switches at default position, reset to defaults
        if (sample_rate - SAMPLE_RATE).abs() < 0.5 {
            let all_default = true;
            if all_default {
                self.s = S_DEFAULT;
                self.a_neg = A_NEG_DEFAULT;
                self.k = K_DEFAULT;
                self.s_ni = S_NI_DEFAULT;

                self.s_be = S_BE_DEFAULT;
                self.k_be = K_BE_DEFAULT;
                self.s_ni_be = S_NI_BE_DEFAULT;
                self.a_neg_be = A_NEG_BE_DEFAULT;

                return;
            }
        }
        self.rebuild_matrices();
    }

    /// Current resistance of runtime resistor `r_ldr` (ohms).
    ///
    /// Read-only accessor; use `set_runtime_R_r_ldr` to update.
    #[inline]
    pub fn r_ldr(&self) -> f64 {
        self.pot_0_resistance
    }

    /// Set runtime resistor `r_ldr` (clamped to [1000.0..1000000.0] ohms).
    ///
    /// Audio-rate safe: no internal smoothing; caller (plugin-side
    /// envelope follower) is the smoother.
    /// Marks matrices dirty. Rebuild deferred to next `process_sample()`.
    pub fn set_runtime_R_r_ldr(&mut self, resistance: f64) {
        if !resistance.is_finite() {
            return;
        }
        let r = resistance.clamp(RUNTIME_R_R_LDR_MIN, RUNTIME_R_R_LDR_MAX);
        if (r - self.pot_0_resistance).abs() < 1e-12 {
            return;
        }
        self.pot_0_resistance = r;
        self.matrices_dirty = true;
        self.noise_thermal_sqrt_inv_r[10] = (1.0 / r).sqrt();
    }

    /// Rebuild all sample-rate-dependent matrices from G/C constants.
    ///
    /// Applies switch/pot deltas to G/C, then rebuilds A, S, K, S*N_i.
    /// Called by `set_switch_N()`, `set_pot_N()`, and `set_sample_rate()`.
    fn rebuild_matrices(&mut self) {
        let internal_rate = self.current_sample_rate * OVERSAMPLING_FACTOR as f64;
        let alpha = 2.0 * internal_rate; // trapezoidal: alpha = 2/T

        // Start from constant G and C matrices
        let mut g_eff = G;
        let c_eff = C;

        // Apply switch position deltas

        // Apply pot conductance deltas (current resistance vs nominal)
        {
            let delta_g = 1.0 / self.pot_0_resistance - POT_0_G_NOM;
            g_eff[6][6] += delta_g;
        }

        // Build A = G_eff + alpha * C_eff
        let mut a = [[0.0f64; N]; N];
        for i in 0..N {
            for j in 0..N {
                a[i][j] = g_eff[i][j] + alpha * c_eff[i][j];
            }
        }

        // Build A_neg: alpha*C - G (trapezoidal)
        let mut a_neg = [[0.0f64; N]; N];
        for i in 0..N {
            for j in 0..N {
                a_neg[i][j] = alpha * c_eff[i][j] - g_eff[i][j];
            }
        }
        // Zero VS/VCVS algebraic rows in A_neg (NOT inductor rows)
        for i in 11..12 {
            for j in 0..N {
                a_neg[i][j] = 0.0;
            }
        }

        // Invert A to get S
        let (s, singular) = invert_n(a);
        if singular {
            self.diag_singular_matrix_count += 1;
        }

        // Compute S * N_i product (N x M)
        let mut s_ni = [[0.0f64; M]; N];
        for i in 0..N {
            for j in 0..M {
                let mut sum = 0.0;
                for kk in 0..N {
                    sum += s[i][kk] * N_I[j][kk];
                }
                s_ni[i][j] = sum;
            }
        }

        // Compute K = N_v * S_NI (M x M)
        let mut k = [[0.0f64; 3]; 3];
        for i in 0..M {
            for j in 0..M {
                let mut sum = 0.0;
                for n_idx in 0..N {
                    sum += N_V[i][n_idx] * s_ni[n_idx][j];
                }
                k[i][j] = sum;
            }
        }

        self.s = s;
        self.a_neg = a_neg;
        self.k = k;
        self.s_ni = s_ni;
    }

    // --- Noise controls (Phase 1) ---

    /// Turn circuit noise on or off. When off, all per-sample RNG calls are skipped.
    pub fn set_noise_enabled(&mut self, on: bool) {
        self.noise_enabled = on;
    }

    /// Master scalar applied to every noise source (post-per-category).
    pub fn set_noise_gain(&mut self, gain: f64) {
        self.noise_gain = gain;
    }

    /// Scalar applied only to Johnson-Nyquist thermal sources.
    pub fn set_thermal_gain(&mut self, gain: f64) {
        self.thermal_gain = gain;
    }

    /// Circuit temperature in Kelvin. 290 K is standard (~16.85 °C).
    /// Cold gear is quieter: 77 K (liquid N2) ≈ −5.76 dB, 3 K ≈ −19.9 dB.
    pub fn set_temperature_k(&mut self, kelvin: f64) {
        if !(kelvin.is_finite() && kelvin > 0.0) {
            return;
        }
        self.temperature_k = kelvin;
        // Recompute thermal_scale at the currently-set sample rate.
        self.noise_thermal_scale = (8.0 * K_B * kelvin * self.noise_fs).sqrt();
    }

    /// Set the master seed. `0` → entropy-seeded from system clock.
    /// Any nonzero value → deterministic (same seed → bit-identical noise).
    pub fn set_seed(&mut self, master: u64) {
        self.noise_master_seed = master;
        self.noise_rng = seed_noise_rngs::<NOISE_THERMAL_N>(master);
        self.noise_gaussian_cache = [None; NOISE_THERMAL_N];
    }
}

/// Invert an N x N matrix via LU factorization + N identity-column back-solves.
///
/// Returns `(result, singular)` where `singular` is `true` if the matrix was
/// detected as singular (pivot below threshold). On singularity, the identity
/// matrix is returned as a safe fallback; the caller should record the event
/// via `diag_singular_matrix_count`.
///
/// Previously used in-place Gauss-Jordan on an augmented `[A | I]` matrix
/// (N × 2N, ~2N³ ops, ~28 KB stack at N = 42). The LU path factors `A = LU`
/// in place (N × N, ~N³/3 ops) and solves `N` back-substitutions
/// (~N³ total), reducing work and stack use while producing identical
/// mathematical output for well-conditioned inputs. Singular-pivot behavior
/// matches the prior implementation byte-for-byte (same 1e-30 threshold,
/// same identity fallback).
fn invert_n(a: [[f64; N]; N]) -> ([[f64; N]; N], bool) {
    // --- 1. LU factorization in place with partial pivoting ---
    //
    // After this loop, `lu` holds L (below diagonal, unit-lower-triangular
    // with implicit 1s) and U (diagonal + above). `perm[i]` is the index
    // of the original row that ended up at row i of LU after pivoting —
    // equivalent to P·A = L·U.
    let mut lu = a;
    let mut perm = [0usize; N];
    for i in 0..N {
        perm[i] = i;
    }

    for k in 0..N {
        // Partial pivoting: find the largest |lu[i][k]| for i >= k.
        let mut max_row = k;
        let mut max_val = lu[k][k].abs();
        for i in (k + 1)..N {
            let v = lu[i][k].abs();
            if v > max_val {
                max_val = v;
                max_row = i;
            }
        }

        if max_val < 1e-30 {
            let mut result = [[0.0f64; N]; N];
            for i in 0..N {
                result[i][i] = 1.0;
            }
            return (result, true);
        }

        if max_row != k {
            lu.swap(k, max_row);
            perm.swap(k, max_row);
        }

        // Eliminate column k below the pivot.
        let pivot = lu[k][k];
        for i in (k + 1)..N {
            let m = lu[i][k] / pivot;
            lu[i][k] = m;
            for j in (k + 1)..N {
                lu[i][j] -= m * lu[k][j];
            }
        }
    }

    // --- 2. Solve `A · result[:, col] = e_col` for each identity column ---
    //
    // Equivalent to `L · U · x = P · e_col`. Each back-solve is O(N²), and
    // `P · e_col` has exactly one nonzero (at the row `i` where
    // `perm[i] == col`), so forward substitution can skip the leading zeros.
    let mut result = [[0.0f64; N]; N];
    for col in 0..N {
        // b ← P · e_col
        let mut b = [0.0f64; N];
        let mut start = N;
        for i in 0..N {
            if perm[i] == col {
                b[i] = 1.0;
                start = i;
                break;
            }
        }

        // Forward substitution: L · y = b. L's diagonal is implicit 1.0.
        // Skip rows before the nonzero since they contribute nothing.
        for i in (start + 1)..N {
            let mut sum = b[i];
            for j in start..i {
                sum -= lu[i][j] * b[j];
            }
            b[i] = sum;
        }

        // Backward substitution: U · x = y. U is stored on + above diagonal.
        for i in (0..N).rev() {
            let mut sum = b[i];
            for j in (i + 1)..N {
                sum -= lu[i][j] * b[j];
            }
            let pivot = lu[i][i];
            if pivot.abs() < 1e-30 {
                // Diagonal became singular during elimination (ill-conditioned
                // input that passed the column-pivot check but collapses here).
                let mut fallback = [[0.0f64; N]; N];
                for k in 0..N {
                    fallback[k][k] = 1.0;
                }
                return (fallback, true);
            }
            b[i] = sum / pivot;
        }

        for i in 0..N {
            result[i][col] = b[i];
        }
    }

    (result, false)
}

