// =============================================================================
// MAIN PROCESS FUNCTION
// =============================================================================

/// Process a single audio sample through the circuit
///
/// # Arguments
/// * `input` - Input voltage at INPUT_NODE
/// * `state` - Mutable circuit state (preserved across calls)
///
/// # Returns
/// Output voltages at OUTPUT_NODES (one per output channel)
#[inline]
pub fn process_sample(input: f64, state: &mut CircuitState) -> [f64; NUM_OUTPUTS] {
    // Validate input — handle NaN, inf, and extreme values
    let input = if input.is_finite() {
        input.clamp(-100.0, 100.0)
    } else {
        0.0
    };

    // Lazy rebuild: process all pot/switch changes in one batch
    if state.matrices_dirty {
        state.rebuild_matrices();
        state.matrices_dirty = false;
    }

    // Flush denormals in state vectors to prevent 50-100x CPU penalty during silence.
    // (Most DAW hosts set FTZ/DAZ, but generated code should not rely on it.)
    for v in state.v_prev.iter_mut() {
        *v = *v + 1e-25 - 1e-25;
    }
    for v in state.i_nl_prev.iter_mut() {
        *v = *v + 1e-25 - 1e-25;
    }

    // Pre-check: force BE if cooldown active from previous ringing detection.
    let force_be = state.be_cooldown > 0;
    if state.be_cooldown > 0 {
        state.be_cooldown -= 1;
    }

    // Step 1: Build RHS vector from history and input
    let mut rhs = build_rhs(input, state.input_prev, state);

    // Authentic circuit noise — Phases 1 (thermal) + 2 (shot).
    // Skipped entirely (zero RNG calls) when noise_enabled is false.
    if state.noise_enabled {
        // Two-draw thermal stamp: w_new + w_prev (Nyquist-zeroed, kTC-calibrated).
        let scale_half = state.noise_thermal_scale * state.noise_gain * state.thermal_gain * 0.5;
        if scale_half != 0.0 {
            for k in 0..NOISE_THERMAL_N {
                let g = gaussian(&mut state.noise_rng[k], &mut state.noise_gaussian_cache[k]);
                let w_new = scale_half * state.noise_thermal_sqrt_inv_r[k] * g;
                let i_n = w_new + state.noise_thermal_w_prev[k];
                state.noise_thermal_w_prev[k] = w_new;
                let ni = NOISE_THERMAL_NODE_I[k];
                let nj = NOISE_THERMAL_NODE_J[k];
                if ni > 0 {
                    rhs[ni - 1] += i_n;
                }
                if nj > 0 {
                    rhs[nj - 1] -= i_n;
                }
            }
        }
    }

    // Step 2: Linear prediction: v_pred = S * rhs
    let v_pred = mat_vec_mul_s(&rhs, state);

    // Step 3: Extract controlling voltages for nonlinear devices
    let p = extract_controlling_voltages(&v_pred);

    // Step 4: Solve M×M nonlinear system via Newton-Raphson
    let i_nl = solve_nonlinear(&p, state);

    // Step 5: Compute final node voltages
    let v = compute_final_voltages(&v_pred, &i_nl, state);

    // Step 6: Update history (no-op, handled by A_neg formulation)
    update_history(&v, state);

    // Step 6b: Backward Euler fallback for trapezoidal instability.
    // Triggers when: (a) trapezoidal NR didn't converge, OR (b) any node voltage
    // exceeds supply rails (trapezoidal ringing artifact), OR (c) previous sample
    // used BE (cooldown: stay on BE until ringing decays).
    // BE is L-stable and damps all oscillatory modes that trapezoidal preserves.
    let nr_failed = state.last_nr_iterations >= 200_u32;
    let ringing = v.iter().take(11).any(|&x| x.abs() > 5.50000000000000000e1);
    let need_be = nr_failed || ringing || force_be;
    let (v, i_nl) = if need_be {
        if nr_failed {
            state.diag_nr_max_iter_count += 1;
        }
        // Set cooldown: stay on BE long enough for trapezoidal ringing to decay.
        // 64 samples ≈ 1.5ms at 44.1kHz — enough for most parasitic modes.
        if ringing || nr_failed {
            state.be_cooldown = 64;
        }
        state.diag_be_fallback_count += 1;
        // Rebuild RHS with backward Euler matrices
        let mut rhs_be = [0.0f64; N];
        for i in 0..N {
            let mut sum = RHS_CONST_BE[i];
            for j in 0..N {
                sum += state.a_neg_be[i][j] * state.v_prev[j];
            }
            for j in 0..M {
                sum += N_I[j][i] * state.i_nl_prev[j];
            }
            rhs_be[i] = sum;
        }
        rhs_be[INPUT_NODE] += input / INPUT_RESISTANCE;
        // BE linear prediction: v_pred_be = S_be * rhs_be
        let mut v_pred_be = [0.0f64; N];
        for i in 0..N {
            let mut sum = 0.0;
            for j in 0..N {
                sum += state.s_be[i][j] * rhs_be[j];
            }
            v_pred_be[i] = sum;
        }
        // BE controlling voltages
        let mut p_be = [0.0f64; M];
        for i in 0..M {
            let mut sum = 0.0;
            for j in 0..N {
                sum += N_V[i][j] * v_pred_be[j];
            }
            p_be[i] = sum;
        }
        // BE NR solve: swap k/k_be so solve_nonlinear uses BE kernel
        std::mem::swap(&mut state.k, &mut state.k_be);
        std::mem::swap(&mut state.s_ni, &mut state.s_ni_be);
        let i_nl_be = solve_nonlinear(&p_be, state);
        std::mem::swap(&mut state.k, &mut state.k_be);
        std::mem::swap(&mut state.s_ni, &mut state.s_ni_be);
        // Recover full v from BE
        let mut v_be = v_pred_be;
        for i in 0..N {
            for j in 0..M {
                v_be[i] += state.s_ni_be[i][j] * i_nl_be[j];
            }
        }

        (v_be, i_nl_be)
    } else {
        (v, i_nl)
    };

    // Step 6c: Global node voltage damping safety net.
    // Threshold scales with max DC OP voltage so tube 250V circuits aren't over-damped.
    let (v, i_nl) = {
        let mut max_delta = 0.0_f64;
        for i in 0..11 {
            let d = (v[i] - state.v_prev[i]).abs();
            if d > max_delta {
                max_delta = d;
            }
        }
        // Adaptive threshold: max(2V, 5% of max DC OP node voltage)
        let mut max_dc = 0.0_f64;
        for i in 0..11 {
            let a = state.dc_operating_point[i].abs();
            if a > max_dc {
                max_dc = a;
            }
        }
        let damp_thresh = max_dc.mul_add(0.05, 2.0);
        if max_delta > damp_thresh {
            // This is a last-ditch safety net that should only fire when the
            // solver has produced a pathological step. A nonzero value here is
            // a symptom that needs investigation, not an acceptable steady-state
            // (per CLAUDE.md: "never use output attenuation to mask simulation
            // errors"). Surfaced via state.diag_voltage_damp_count.
            state.diag_voltage_damp_count = state.diag_voltage_damp_count.saturating_add(1);
            let damp = (damp_thresh / max_delta).max(0.01);
            let mut v_d = v;
            for i in 0..N {
                v_d[i] = state.v_prev[i] + damp * (v[i] - state.v_prev[i]);
            }
            let mut i_d = i_nl;
            for i in 0..M {
                i_d[i] = state.i_nl_prev[i] + damp * (i_nl[i] - state.i_nl_prev[i]);
            }
            (v_d, i_d)
        } else {
            (v, i_nl)
        }
    };

    // Step 7: Check for NaN/inf BEFORE updating state (prevents corruption of v_prev/i_nl_prev)
    if !v.iter().all(|x| x.is_finite()) {
        state.v_prev = state.dc_operating_point;
        state.i_nl_prev = DC_NL_I;
        state.i_nl_prev_prev = DC_NL_I;

        state.input_prev = 0.0;
        state.pot_0_resistance = 9.99999999999999854e4;
        state.pot_0_resistance_prev = 9.99999999999999854e4;
        state.be_cooldown = 0;
        state.diag_nan_reset_count += 1;
        // Return DC operating point output instead of zero to avoid discontinuity
        let mut dc_output = [0.0f64; NUM_OUTPUTS];
        for out_idx in 0..NUM_OUTPUTS {
            let raw = state.dc_operating_point[OUTPUT_NODES[out_idx]];
            dc_output[out_idx] = (raw * OUTPUT_SCALES[out_idx]).clamp(-10.0, 10.0);
        }
        return dc_output;
    }

    // Update state for next iteration
    state.v_prev = v;
    state.i_nl_prev_prev = state.i_nl_prev;
    state.i_nl_prev = i_nl;
    state.input_prev = input;

    // (NaN check already done in Step 7, before state update)

    if state.last_nr_iterations >= 200_u32 {
        state.diag_nr_max_iter_count += 1;
    }

    // Step 9: Extract outputs and scale
    let mut output = [0.0f64; NUM_OUTPUTS];
    for out_idx in 0..NUM_OUTPUTS {
        let raw_out = v[OUTPUT_NODES[out_idx]];
        let raw_out = if raw_out.is_finite() { raw_out } else { 0.0 };
        let scaled = raw_out * OUTPUT_SCALES[out_idx];
        let abs_out = scaled.abs();
        if abs_out > state.diag_peak_output {
            state.diag_peak_output = abs_out;
        }
        output[out_idx] = if scaled.is_finite() { scaled } else { 0.0 };
    }
    output
}
